import{_ as e,c as o,o as c,a2 as a}from"./chunks/framework.4NWBWe1O.js";const t="/weblog/assets/canteen.DnR5bYnX.png",h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"src/resume/项目.md","filePath":"src/resume/项目.md"}'),s={name:"src/resume/项目.md"},p=a('<p>2022-06-22 ~ 2023-04 pci-商用部门 <img src="'+t+'" alt="农业智慧食堂"></p><p>2022-06-22 ~ 08-22 <code>广州健康驿站-H5人脸机</code> 为定制安卓人脸设备开发前端交互应用。运行于 webview；</p><p><code>face3.0 人脸管理后台</code> 针对 楼宇人脸机 进行管理，其中包括 人脸登记、授权，人脸下发。记录查阅，访客预约等功能。 基于 vue2 浏览器、公众号挂载的 h5 页面；</p><p><code>朗国x2500鸿蒙机人脸机demo</code> 开发： 首次接触鸿蒙 hap 开发，经过数月的开发、实践。在对鸿蒙 hap 还处于较为浅薄的情况下，发表一下自己的个人感想，以下内容仅代表个人看法。仅供参考，如有不当之处,请予指正。</p><ol><li>X2500 在兼容轻量级 openHarmony 的类 Web 开发语法上，是完整、稳定的，满足轻量应用的开发需求</li><li>采用 JS 编程，降低学习开发的成本，容易上手。也正符合鸿蒙系统采用 ets 逐步取代 java 编程的趋势</li><li>存在一些开发上的误导现象，eg：JS 模块化在语法上采用 ESM 规范，其中 ESM 规范是值的动态映射，但具体使用中，则和 cjs 的值拷贝类似。</li><li>缺少真机调试的有效手段</li><li>目前的 x2500 在应用层面上的开发，未体现出 openHarmony 系统的独特能力，在页面开发能力上有一定的局限性</li></ol><p><code>acs-device-manage</code> 地铁门禁管理系统 table，form 等万金油基础组件开发；router、permission 等</p><p><code>edge-box-manage</code> 边缘小站 - 盒子管理系统</p><p><code>视频云平台</code></p><p><code>交通管理助手 - 大模型问答界面</code></p><p>\\ 杂七杂八定制啊外包项目开发；</p>',10),r=[p];function n(_,d,i,l,m,f){return c(),o("div",null,r)}const S=e(s,[["render",n]]);export{h as __pageData,S as default};
